def get_object(self):
        return AbstractNode.objects.filter(
            guids___id=self.kwargs['guid']
        ).annotate(
            guid=F('guids___id'),
            public_cap=Case(
                When(
                    custom_storage_usage_limit_public=None,
                    then=settings.STORAGE_LIMIT_PUBLIC,
                ),
                When(
                    custom_storage_usage_limit_public__gt=0,
                    then=F('custom_storage_usage_limit_public'),
                ),
                output_field=IntegerField()
            ),
            private_cap=Case(
                When(
                    custom_storage_usage_limit_private=None,
                    then=settings.STORAGE_LIMIT_PRIVATE,
                ),
                When(
                    custom_storage_usage_limit_private__gt=0,
                    then=F('custom_storage_usage_limit_private'),
                ),
                output_field=IntegerField()
            )
        ).get()

def post(self, request, *args, **kwargs):
        user = self.get_object()
        if user.date_disabled is None:
            user.deactivate_account()
            update_admin_log(
                user_id=self.request.user.id,
                object_id=user.pk,
                object_repr='User',
                message=f'User account {user.pk} disabled',
                action_flag=USER_REMOVED
            )
            NotificationTypeEnum.USER_REQUEST_DEACTIVATION_COMPLETE.instance.emit(
                user=user,
                event_context={
                    'user_fullname': user.fullname,
                    'contact_email': OSF_SUPPORT_EMAIL,
                }
            )
        else:
            user.reactivate_account()
            update_admin_log(
                user_id=self.request.user.id,
                object_id=user.pk,
                object_repr='User',
                message=f'User account {user.pk} reenabled',
                action_flag=USER_RESTORED
            )
        user.save()

        return redirect(self.get_success_url())

