def edit_node(auth, node, **kwargs):
    post_data = request.json
    edited_field = post_data.get('name')
    value = post_data.get('value', '')

    new_val = None
    if edited_field == 'title':
        try:
            node.set_title(value, auth=auth)
        except ValidationError as e:
            raise HTTPError(
                http_status.HTTP_400_BAD_REQUEST,
                data=dict(message_long=str(e))
            )
        new_val = node.title
    elif edited_field == 'description':
        node.set_description(value, auth=auth)
        new_val = node.description
    elif edited_field == 'category':
        node.category = new_val = value

    try:
        node.save()
    except ValidationError as e:
        raise HTTPError(
            http_status.HTTP_400_BAD_REQUEST,
            data=dict(message_long=str(e))
        )
    return {
        'status': 'success',
        'newValue': new_val  # Used by x-editable  widget to reflect changes made by sanitizer
    }

def rate_object(request, ct, pk, score=1, add=True):
    if request.method != "POST" and not ALLOW_GET:
        err_msg = f'Invalid request method: "{request.method}". Must be POST.'
        return HttpResponseNotAllowed(err_msg)

    redirect_url = (
        request.POST.get("next") or request.GET.get("next") or request.META.get("HTTP_REFERER")
    )
    if redirect_url and not url_has_allowed_host_and_scheme(redirect_url, settings.ALLOWED_HOSTS):
        return HttpResponseBadRequest("Invalid next URL.")
    if not redirect_url:
        redirect_url = "/"

    ctype = get_object_or_404(ContentType, pk=ct)
    model_class = ctype.model_class()

    if not hasattr(model_class, "_ratings_field"):
        err_msg = f"Model class {model_class} does not support ratings"
        raise Http404(err_msg)

    obj = get_object_or_404(model_class, pk=pk)

    ratings_descriptor = getattr(obj, obj._ratings_field)

    if add:
        ratings_descriptor.rate(request.user, score)
    else:
        ratings_descriptor.unrate(request.user)

    if request.is_ajax():
        return HttpResponse('{"success": true}', content_type="application/json")
    return HttpResponseRedirect(redirect_url)

def require_sudo_mode(f: ViewFunc) -> ViewFunc:
    @wraps(f)
    def wrapper(request: HttpRequest, *args: Any, **kwds: Any) -> HttpResponse:
        assert request.user.is_authenticated

        # is sudo mode active and has not expired yet?
        if _session_unsign(request, "sudo", 1800) == "active":
            return f(request, *args, **kwds)

        if not TokenBucket.authorize_sudo_code(request.user):
            return render(request, "try_later.html")

        # has the user submitted a code to enter sudo mode?
        if "sudo_code" in request.POST:
            ours = _session_unsign(request, "sudo_code", 900)
            if ours and ours == request.POST["sudo_code"]:
                request.session.pop("sudo_code")
                request.session["sudo"] = TimestampSigner().sign("active")
                return redirect(request.path)

        if not _session_unsign(request, "sudo_code", 900):
            code = "%06d" % secrets.randbelow(1000000)
            request.session["sudo_code"] = TimestampSigner().sign(code)
            emails.sudo_code(request.user.email, {"sudo_code": code})

        ctx = {}
        if "sudo_code" in request.POST:
            ctx["wrong_code"] = True

        return render(request, "accounts/sudo.html", ctx)

    return wrapper

def get_token_value(self, request):
        auth_header = get_authorization_header(request).split()
        expected_header_prefix = self.auth_header_prefix.upper()

        if not auth_header or (
            smart_str(auth_header[0].upper()) != expected_header_prefix
        ):
            return None

        if len(auth_header) == 1:
            msg = {
                'detail': gettext(
                    'Invalid Authorization header. No credentials provided.'
                ),
                'code': 'ERROR_INVALID_HEADER',
            }
            raise exceptions.AuthenticationFailed(msg)
        elif len(auth_header) > 2:
            msg = {
                'detail': gettext(
                    'Invalid Authorization header. Credentials string should not '
                    'contain spaces.'
                ),
                'code': 'ERROR_INVALID_HEADER',
            }
            raise exceptions.AuthenticationFailed(msg)

        return auth_header[1]

def _send_request_to_dnsaas(
        self, request_method: str, url: str, json_data: dict = None
    ) -> requests.Response:
        try:
            response = self.session.request(
                method=request_method,
                url=url,
                json=json_data,
                timeout=float(settings.DNSAAS_TIMEOUT),
            )
            logger.info(
                "Sent {} request to DNSaaS to {}".format(request_method, url),
                extra={
                    "request_data": json.dumps(json_data),
                    "response_status": response.status_code,
                    "response_content": response.text,
                },
            )

            return response
        except Exception:
            logger.exception(
                "Sending {} request to DNSaaS to {} failed.".format(
                    request_method, url
                ),
                extra={"request_data": json.dumps(json_data)},
            )
            raise

def create_bucket(auth, node_addon, **kwargs):
    bucket_name = request.json.get('bucket_name', '')
    bucket_location = request.json.get('bucket_location', '')

    if not utils.validate_bucket_name(bucket_name):
        return {
            'message': 'That bucket name is not valid.',
            'title': 'Invalid bucket name',
        }, http_status.HTTP_400_BAD_REQUEST

    # Get location and verify it is valid
    if not utils.validate_bucket_location(bucket_location):
        return {
            'message': 'That bucket location is not valid.',
            'title': 'Invalid bucket location',
        }, http_status.HTTP_400_BAD_REQUEST

    try:
        utils.create_bucket(node_addon, bucket_name, bucket_location)
    except exceptions.NoCredentialsError as e:
        return {
            'message': str(e),
            'title': 'Problem connecting to S3',
        }, http_status.HTTP_400_BAD_REQUEST
    except exceptions.ClientError as e:
        return {
            'message': str(e),
            'title': f"Problem creating bucket '{bucket_name}'",
        }, http_status.HTTP_400_BAD_REQUEST

    return {}

def edit_wiki_settings(node, auth, **kwargs):
    wiki_settings = node.get_addon('wiki')
    permissions = request.get_json().get('permission', None)

    if not wiki_settings:
        raise HTTPError(http_status.HTTP_400_BAD_REQUEST, data=dict(
            message_short='Invalid request',
            message_long='Cannot change wiki settings without a wiki'
        ))

    if permissions == 'public':
        permissions = True
    elif permissions == 'private':
        permissions = False
    else:
        raise HTTPError(http_status.HTTP_400_BAD_REQUEST, data=dict(
            message_short='Invalid request',
            message_long='Permissions flag used is incorrect.'
        ))

    try:
        wiki_settings.set_editing(permissions, auth, log=True)
    except NodeStateError as e:
        raise HTTPError(http_status.HTTP_400_BAD_REQUEST, data=dict(
            message_short="Can't change privacy",
            message_long=str(e)
        ))

    return {
        'status': 'success',
        'permissions': permissions,
    }

def must_be_signed(func):
    @wraps(func)
    def wrapped(*args, **kwargs):
        if request.method in ('GET', 'DELETE'):
            data = request.args
        else:
            data = request.get_json()

        try:
            sig = data['signature']
            payload = signing.unserialize_payload(data['payload'])
            exp_time = payload['time']
        except (KeyError, ValueError):
            raise HTTPError(http_status.HTTP_400_BAD_REQUEST, data={
                'message_short': 'Invalid payload',
                'message_long': 'The request payload could not be deserialized.'
            })

        if not signing.default_signer.verify_payload(sig, payload):
            raise HTTPError(http_status.HTTP_401_UNAUTHORIZED)

        if time() > exp_time:
            raise HTTPError(http_status.HTTP_400_BAD_REQUEST, data={
                'message_short': 'Expired',
                'message_long': 'Signature has expired.'
            })

        kwargs['payload'] = payload
        return func(*args, **kwargs)
    return wrapped

