def form_valid(self, form):
        saved_objects = []
        args = [form.cleaned_data[field["field"]] for field in self.fields]
        for data in zip(*args):
            for field in self._get_ancestors_pointers(self.obj):
                setattr(self.obj, field, None)
            self.obj.id = self.obj.pk = None

            for field in self.clear_fields:
                setattr(self.obj, field["field"], field["value"])

            for i, field in enumerate(self.fields):
                setattr(self.obj, field["field"], data[i])

            try:
                self.obj.clean()
            except ValidationError as exc:
                for error in exc:
                    form.add_error(error[0], error[1])
                return self.form_invalid(form)

            self.obj.save()
            saved_objects.append(
                '<a href="{}">{}</a>'.format(self.obj.get_absolute_url(), str(self.obj))
            )

        messages.success(
            self.request,
            mark_safe(
                _("Saved %(count)d object(s): %(objects)s")
                % {"count": len(saved_objects), "objects": ", ".join(saved_objects)}
            ),
        )
        return HttpResponseRedirect(self.get_url_name())

def handle(self, *args, **options):
        # Nextcloud scan
        if options["nextcloud"]:
            self.nextcloud_scan()
            return

        # Add a single file.
        if options["scan_files"]:
            scan_files = options["scan_files"]
            deleted_user: User = get_deleted_user()
            for user in User.objects.all():
                user_files = []
                if user == deleted_user:
                    continue
                for scan_file in scan_files:
                    if scan_file.startswith(user.scan_directory):
                        user_files.append(scan_file)
                if user_files:
                    scan_photos(user, False, uuid.uuid4(), scan_files=user_files)
            return

        # Directory scan
        deleted_user: User = get_deleted_user()
        for user in User.objects.all():
            if user != deleted_user:
                scan_photos(
                    user, options["full_scan"], uuid.uuid4(), user.scan_directory
                )

def task_source_process_document(source_id, dry_run=False):
    Source = apps.get_model(
        app_label='sources', model_name='Source'
    )

    lock_id = 'task_source_process_document-%d' % source_id
    try:
        logger.debug('trying to acquire lock: %s', lock_id)
        lock = LockingBackend.get_backend().acquire_lock(
            name=lock_id, timeout=DEFAULT_SOURCES_LOCK_EXPIRE
        )
    except LockError:
        logger.debug('unable to obtain lock: %s' % lock_id)
    else:
        logger.debug('acquired lock: %s', lock_id)

        try:
            source = Source.objects.get(pk=source_id)
            if source.enabled or dry_run:
                source.get_backend_instance().process_documents(dry_run=dry_run)
        except Exception as exception:
            logger.error(
                'Error processing source id: %s; %s', source_id, exception,
                exc_info=True
            )
            if settings.DEBUG:
                raise
            else:
                source.error_log.create(
                    text='{}; {}'.format(
                        exception.__class__.__name__, exception
                    )
                )
        else:
            source.error_log.all().delete()
        finally:
            lock.release()

def handle(self, *args: Any, **options: Any) -> None:
        if (not options["api_key"] and not options["email"]) or (
            options["api_key"] and options["email"]
        ):
            raise CommandError("Please enter either an email or API key to manage")

        realm = self.get_realm(options)
        if options["email"]:
            user_profile = self.get_user(options["email"], realm)
        else:
            try:
                user_profile = get_user_profile_by_api_key(options["api_key"])
            except UserProfile.DoesNotExist:
                raise CommandError(
                    "Unable to get user profile for API key {}".format(options["api_key"])
                )

        users = [user_profile]
        if options["bots"]:
            users.extend(
                bot for bot in UserProfile.objects.filter(is_bot=True, bot_owner=user_profile)
            )

        operation = options["operation"]
        for user in users:
            print(f"Applying operation to User ID: {user.id}: {operation}")

            if operation == "block":
                RateLimitedUser(user, domain=options["domain"]).block_access(options["seconds"])
            elif operation == "unblock":
                RateLimitedUser(user, domain=options["domain"]).unblock_access()

def handle(self, *args, **options):
        certs_dir = options["certs_dir"]
        repository_name = options["repository_name"]
        if not os.path.isdir(certs_dir):
            self.stdout.write(
                self.style.ERROR(
                    "Dir {} not found. Please check certs_dir option.".format(certs_dir)
                )
            )
            return
        for root, dirs, files in os.walk(certs_dir):
            for filename in fnmatch.filter(files, "*.crt"):
                cert = None
                pem_data = None
                try:
                    with open(os.path.join(root, filename)) as f:
                        pem_data = f.read()
                except IOError:
                    continue
                try:
                    cert = x509.load_pem_x509_certificate(
                        pem_data.encode(), default_backend()
                    )
                except ValueError:
                    self.stderr.write("{}/{} is not valid\n".format(root, filename))
                    continue
                if cert.not_valid_after < datetime.datetime.now():
                    continue
                self.get_data_from_cert(cert, filename, repository_name)

def _render_email_html(notification_type, ctx: dict) -> str:
    template_text = notification_type.template
    if not template_text:
        return ''

    uri = _inline_uri_for_db_template()
    text = template_text
    if NOTIFY_BASE_URI:
        text = INHERIT_RX.sub(rf'\1\2{NOTIFY_BASE_URI}\2', text, count=1)

    # If using notify_base, merge in defaults
    if 'notify_base' in text or 'notify_base' in (uri or ''):
        for k, v in NOTIFY_BASE_DEFAULTS.items():
            ctx.setdefault(k, v)

    try:
        return MakoTemplate(
            text=text,
            lookup=MAKO_LOOKUP,
            uri=uri,
            strict_undefined=True,
        ).render(**(ctx or {}))

    except Exception:
        logging.exception(
            f'Mako render failed. type {notification_type.name} provided_keys=%s inline_uri=%s base_uri=%s lookup_dirs=%s',
            sorted((ctx or {}).keys()), uri, NOTIFY_BASE_URI, LOOKUP_DIRS,
        )
        raise Exception(f'Failed to render email template {notification_type.name}')

def main():

    # drop all styles
    CitationStyle.objects.all().delete()

    total = 0

    for style_file in get_style_files(settings.CITATION_STYLES_PATH):
        with open(style_file) as f:
            try:
                root = etree.parse(f).getroot()
            except etree.XMLSyntaxError:
                continue
            total += 1
            namespace = root.nsmap.get(None)
            selector = '{{{ns}}}info/{{{ns}}}'.format(ns=namespace)

            # Required
            fields = {
                '_id': os.path.splitext(os.path.basename(style_file))[0],
                'title': root.find(selector + 'title').text,
                'has_bibliography': True if root.find(
                    '{{{ns}}}{tag}'.format(ns=namespace, tag='bibliography')) is not None else False
            }

            # Optional
            try:
                fields['short_title'] = root.find(selector + 'title-short').text
            except AttributeError:
                pass

            try:
                fields['summary'] = root.find(selector + 'summary').text
            except AttributeError:
                pass

            style = CitationStyle(**fields)
            style.save()

    return total

def queryset(self, request, queryset):
        value = self.value()
        if not value:
            ids = []
        else:
            ids = value.split(",")
        q_param = Q()
        for id_ in ids:
            if id_ == self.empty_value:
                q_param |= Q(**{"{}__isnull".format(self.field_path): True})
            else:
                q_param |= Q(
                    **{
                        "{}__in".format(self.field_path): self._get_descendants(
                            request, id_
                        )
                    }
                )
        try:
            queryset = queryset.filter(q_param)
        except ValueError:
            messages.warning(
                request,
                _('Incorrect value in "%(field_name)s" filter')
                % {"field_name": self.title},
            )
            raise IncorrectLookupParameters()
        return queryset
